/**
 * Push Notification service for Aura Alpha.
 *
 * On web (PWA): uses Firebase Cloud Messaging.
 * On native (Capacitor iOS/Android): uses @capacitor/push-notifications if available.
 * Falls back to a no-op stub when neither is available.
 *
 * Lazy-initializes Firebase only when VITE_FIREBASE_API_KEY is set.
 */
import { Capacitor } from '@capacitor/core';
import { apiPost } from '../utils/api';

// ---------------------------------------------------------------------------
// Internal state
// ---------------------------------------------------------------------------
let _firebaseApp = null;
let _messaging = null;
let _cachedToken = null;
let _initialized = false;

const VAPID_KEY = import.meta.env.VITE_FIREBASE_VAPID_KEY || '';

// ---------------------------------------------------------------------------
// Firebase lazy init (web only)
// ---------------------------------------------------------------------------
async function _initFirebase() {
  if (_firebaseApp) return true;

  const apiKey = import.meta.env.VITE_FIREBASE_API_KEY;
  if (!apiKey) {
    console.warn('[Push] VITE_FIREBASE_API_KEY not set — push notifications disabled');
    return false;
  }

  try {
    const { initializeApp } = await import('firebase/app');
    const { getMessaging, isSupported } = await import('firebase/messaging');

    const supported = await isSupported();
    if (!supported) {
      console.warn('[Push] Firebase messaging not supported in this browser');
      return false;
    }

    _firebaseApp = initializeApp({
      apiKey,
      authDomain:        import.meta.env.VITE_FIREBASE_AUTH_DOMAIN        || '',
      projectId:         import.meta.env.VITE_FIREBASE_PROJECT_ID         || '',
      storageBucket:     import.meta.env.VITE_FIREBASE_STORAGE_BUCKET     || '',
      messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID || '',
      appId:             import.meta.env.VITE_FIREBASE_APP_ID             || '',
    });

    _messaging = getMessaging(_firebaseApp);
    return true;
  } catch (err) {
    console.error('[Push] Firebase init failed:', err);
    return false;
  }
}

// ---------------------------------------------------------------------------
// Capacitor native path
// ---------------------------------------------------------------------------
let _capacitorPush = null;

async function _initCapacitor() {
  try {
    // Dynamic string to prevent Rollup from resolving at build time
    const modName = '@capacitor/' + 'push-notifications';
    const mod = await import(/* @vite-ignore */ modName);
    _capacitorPush = mod.PushNotifications;
    return true;
  } catch {
    return false;
  }
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Request notification permission and obtain an FCM/APNs push token.
 * Returns the token string or null if unavailable.
 */
export async function initPush() {
  if (_initialized && _cachedToken) return _cachedToken;

  // Native path (iOS/Android)
  if (Capacitor.isNativePlatform()) {
    const ok = await _initCapacitor();
    if (!ok) {
      console.warn('[Push] @capacitor/push-notifications not available');
      _initialized = true;
      return null;
    }

    const perm = await _capacitorPush.requestPermissions();
    if (perm.receive !== 'granted') {
      console.warn('[Push] Native permission denied');
      _initialized = true;
      return null;
    }

    await _capacitorPush.register();

    return new Promise((resolve) => {
      _capacitorPush.addListener('registration', (tokenData) => {
        _cachedToken = tokenData.value;
        _initialized = true;
        resolve(_cachedToken);
      });
      _capacitorPush.addListener('registrationError', (err) => {
        console.error('[Push] Native registration error:', err);
        _initialized = true;
        resolve(null);
      });
    });
  }

  // Web path (FCM)
  const ok = await _initFirebase();
  if (!ok) {
    _initialized = true;
    return null;
  }

  try {
    const permission = await Notification.requestPermission();
    if (permission !== 'granted') {
      console.warn('[Push] Web notification permission denied');
      _initialized = true;
      return null;
    }

    const { getToken: fcmGetToken } = await import('firebase/messaging');

    // Register the FCM service worker
    const swReg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');

    _cachedToken = await fcmGetToken(_messaging, {
      vapidKey: VAPID_KEY,
      serviceWorkerRegistration: swReg,
    });

    _initialized = true;
    return _cachedToken;
  } catch (err) {
    console.error('[Push] Token retrieval failed:', err);
    _initialized = true;
    return null;
  }
}

/**
 * Register the current FCM token with the Aura Alpha backend.
 * Call this after login when a valid auth token is in localStorage.
 */
export async function registerTokenWithBackend() {
  const token = _cachedToken;
  if (!token) return;

  const platform = Capacitor.isNativePlatform() ? 'ios' : 'web';
  try {
    await apiPost('/notifications/register-device', { token, platform });
    // Token registered successfully
  } catch (err) {
    console.warn('[Push] Backend registration failed:', err);
  }
}

/**
 * Initialize push and register token in one call.
 * Convenience method to call after successful login.
 */
export async function initPushAndRegister() {
  const token = await initPush();
  if (token) {
    await registerTokenWithBackend();
  }
  return token;
}

/**
 * Listen for foreground push messages (web only via FCM).
 * On native, use @capacitor/push-notifications listener directly.
 * @param {function} callback - receives { title, body, data }
 * @returns {function|null} unsubscribe function, or null
 */
export async function onMessage(callback) {
  if (!callback) return null;

  // Native path
  if (Capacitor.isNativePlatform()) {
    if (!_capacitorPush) {
      const ok = await _initCapacitor();
      if (!ok) return null;
    }
    const listener = await _capacitorPush.addListener(
      'pushNotificationReceived',
      (notification) => {
        callback({
          title: notification.title || '',
          body:  notification.body  || '',
          data:  notification.data  || {},
        });
      }
    );
    return () => listener.remove();
  }

  // Web path
  const ok = await _initFirebase();
  if (!ok || !_messaging) return null;

  const { onMessage: fcmOnMessage } = await import('firebase/messaging');
  const unsub = fcmOnMessage(_messaging, (payload) => {
    callback({
      title: payload.notification?.title || '',
      body:  payload.notification?.body  || '',
      data:  payload.data               || {},
    });
  });
  return unsub;
}

/**
 * Return the cached FCM/APNs token (or null if not yet initialized).
 */
export function getToken() {
  return _cachedToken;
}

export default { initPush, initPushAndRegister, registerTokenWithBackend, onMessage, getToken };
